body {
    font-family: Arial, sans-serif;
    font-size: 13px;
    color: #000;
    margin: 0;
}

body * {
    font-family: Arial, sans-serif;
    font-size: 13px;
    line-height: 1.5em;
    box-sizing: border-box;
}

.title {
    font-size: 20px;
    font-weight: bold;
    text-align: center;
    padding-bottom: 4px;
}

.section-label {
    font-weight: bold;
    font-size: 20px;
}

table.outer {
    width: 100%;
    border: none;
    margin-bottom: 10px;
}

table.outer td {
    vertical-align: top;
    padding: 4px;
}

table.data-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 10px;
}

table.data-table th,
table.data-table td {
    border: 1px solid #000;
    padding: 6px;
    text-align: center;
}

table.data-table th {
    background-color: #f5f5f5;
    font-weight: bold;
}

.text-left {
    text-align: left !important;
}

.child-arrow {
    padding-left: 8px;
    padding-right: 6px;
    display: inline-block;
}

table.signature-table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 10px;
}

table.signature-table td {
    border: none !important;
    text-align: center;
    padding-top: 30px;
    font-weight: bold;
}

.footer {
    border-top: 2px solid #000;
    font-size: 10px;
    text-align: center;
    margin-top: 50px;
    padding-top: 8px;
    line-height: 1.6;
}

.mcp-head-row {
    margin-top: 10px;
    margin-bottom: 10px;
}

.mcp-item-line,
.mcp-date-line {
    font-size: 18px;
    font-weight: bold;
    margin-bottom: 6px;
}

.sheet-block {
    margin-top: 28px;
    page-break-inside: avoid;
}

.plan-header-table {
    margin-top: 8px;
    margin-bottom: 22px;
}

.sheet-diagram-wrap {
    margin-top: 18px;
    margin-bottom: 18px;
}

.sheet-length-label {
    text-align: center;
    font-size: 16px;
    font-weight: bold;
    line-height: 1.2;
}

.sheet-length-label.top {
    margin-bottom: 8px;
}

.sheet-length-label.bottom {
    margin-top: 8px;
}

.diagram-row {
    display: flex;
    align-items: center;
    gap: 12px;
}

.sheet-width-label {
    writing-mode: vertical-rl;
    transform: rotate(180deg);
    font-size: 16px;
    font-weight: bold;
    min-width: 26px;
    text-align: center;
}

.sheet-canvas {
    position: relative;
    border: 2px solid #000;
    background: #fff;
    overflow: hidden;
}

.sheet-center-title {
    position: absolute;
    top: 8px;
    left: 0;
    width: 100%;
    text-align: center;
    z-index: 2;
    pointer-events: none;
}

.sheet-center-code {
    font-size: 22px;
    font-weight: bold;
    line-height: 1.2;
}

.sheet-center-name {
    font-size: 16px;
    line-height: 1.2;
}

.piece {
    position: absolute;
    border: 1px dashed #666;
    overflow: hidden;
    display: flex;
    align-items: center;
    justify-content: center;
    text-align: center;
    padding: 2px;
    z-index: 1;
}

.piece-fg {
    background: rgba(255,255,255,0.7);
    border: 1px dashed #555;
}

.piece-leftover {
    background: rgba(242,242,242,0.75);
    border: 1px dashed #777;
}

.piece-waste {
    background: rgba(221,221,221,0.85);
    border: 1px dashed #777;
}

.piece-inner {
    width: 100%;
    font-size: 10px;
    line-height: 1.1;
}

.piece-main {
    font-size: 11px;
    font-weight: bold;
}

.piece-sub {
    font-size: 9px;
}

.sheet-loss-table {
    border-top: 1px solid #999;
    border-bottom: 1px solid #999;
    padding-top: 8px;
    padding-bottom: 8px;
}

.sheet-loss-table td {
    padding-top: 10px;
    padding-bottom: 10px;
    font-size: 16px;
}

.page-break {
    page-break-after: always;
}
